mapper.select:
SELECT fr.*, c.`name` as consultingName FROM elder_consulting_follow_record fr LEFT JOIN elder_consulting c ON fr.consulting_id = c.id WHERE fr.del_flag = 0 AND fr.consulting_id = #{data.consultingId}
AND fr.receptionist_name LIKE concat(concat('%',#{data.receptionistName}),'%')
ORDER BY fr.create_time DESC
